var program = require('commander');
program
    .version(require('./package').version)
    .option('update', '更新当前本地分支')
    .option('commit', '保存本地代码')
    .option('push', '将本地代码提交到远程分支')
    .option('create', '创建本地分支')
    .option('-g, --group [group]', '事业部分组', 'job')
    .option('-t, --test [bol]', '是否为测试分支(仅内部测试)')
    .parse(process.argv);

var funGetArguments = require('./get-arguments');
var log = require('./log.js');
var group = 'job';
var strBranchDic = 'presandbox';
var obj_args = funGetArguments('type');
if(typeof program.group != undefined){
  group = program.group;
}
if(program.test){
  log.out('这是测试分支');
  strBranchDic = 'ikun_test';
}
if(!obj_args['type']){
  log.out('必须加参数（update|commit|push|create）');
  return;
}
var git = require('./core')(obj_args['type'], strBranchDic, group);
git.fire();